mapper.select:
select period_id periodId, period_code periodCode, start_date startDate, end_date endDate, close_status closeStatus, close_by closeBy, close_time closeTime, create_time createTime, remark from fin_account_period
and period_code like concat('%', #{periodCode}, '%') and close_status = #{closeStatus}
order by period_code desc

select subject_id subjectId, subject_code subjectCode, subject_name subjectName, subject_type subjectType, parent_code parentCode, balance_direction balanceDirection, status, create_time createTime, remark from fin_account_subject
and subject_code like concat('%', #{subjectCode}, '%') and subject_name like concat('%', #{subjectName}, '%') and subject_type = #{subjectType} and status = #{status}
order by subject_code

select fee_type_id feeTypeId, fee_code feeCode, fee_name feeName, fee_category feeCategory, default_subject_code defaultSubjectCode, allocate_rule allocateRule, status, create_time createTime, remark from fin_fee_type
and fee_code like concat('%', #{feeCode}, '%') and fee_name like concat('%', #{feeName}, '%') and fee_category = #{feeCategory} and status = #{status}
order by fee_type_id desc

select platform_account_id platformAccountId, platform_code platformCode, platform_name platformName, shop_id shopId, shop_name shopName, account_no accountNo, currency, status, create_time createTime, remark from fin_platform_account
and platform_code = #{platformCode} and shop_name like concat('%', #{shopName}, '%') and account_no like concat('%', #{accountNo}, '%') and status = #{status}
order by platform_account_id desc

select bank_account_id bankAccountId, account_name accountName, bank_name bankName, bank_no bankNo, currency, opening_balance openingBalance, status, create_time createTime, remark from fin_bank_account
and account_name like concat('%', #{accountName}, '%') and bank_name like concat('%', #{bankName}, '%') and bank_no like concat('%', #{bankNo}, '%') and status = #{status}
order by bank_account_id desc

select s.settlement_id settlementId, s.settlement_no settlementNo, s.platform_code platformCode, s.platform_name platformName, s.shop_id shopId, s.shop_name shopName, s.period_code periodCode, s.bill_start_date billStartDate, s.bill_end_date billEndDate, s.income_amount incomeAmount, s.refund_amount refundAmount, s.commission_fee commissionFee, s.payment_fee paymentFee, s.ad_fee adFee, s.service_fee serviceFee, s.freight_fee freightFee, s.other_fee otherFee, s.receivable_amount receivableAmount, s.received_amount receivedAmount, s.diff_amount diffAmount, s.settlement_status settlementStatus, s.reconcile_status reconcileStatus, s.source_file sourceFile, s.create_time createTime, s.remark, ar.receivable_no receivableNo, v.voucher_no voucherNo from fin_platform_settlement s left join fin_receivable_bill ar on ar.source_type = 'settlement' and ar.source_no = s.settlement_no left join fin_voucher v on v.source_type = 'settlement' and v.source_no = s.settlement_no
and s.settlement_no like concat('%', #{settlementNo}, '%') and s.period_code = #{periodCode} and s.shop_name like concat('%', #{shopName}, '%') and s.settlement_status = #{settlementStatus} and s.reconcile_status = #{reconcileStatus}
order by s.settlement_id desc

select receivable_id receivableId, receivable_no receivableNo, source_type sourceType, source_no sourceNo, counterparty_type counterpartyType, counterparty_id counterpartyId, counterparty_name counterpartyName, shop_id shopId, shop_name shopName, period_code periodCode, bill_amount billAmount, writeoff_amount writeoffAmount, remain_amount remainAmount, due_date dueDate, bill_status billStatus, create_time createTime, remark from fin_receivable_bill
and receivable_no like concat('%', #{receivableNo}, '%') and period_code = #{periodCode} and counterparty_name like concat('%', #{counterpartyName}, '%') and shop_name like concat('%', #{shopName}, '%') and bill_status = #{billStatus}
order by receivable_id desc

select p.payable_id payableId, p.payable_no payableNo, p.source_type sourceType, p.source_no sourceNo, p.counterparty_type counterpartyType, p.counterparty_id counterpartyId, p.counterparty_name counterpartyName, p.period_code periodCode, p.bill_amount billAmount, p.writeoff_amount writeoffAmount, p.remain_amount remainAmount, p.due_date dueDate, p.bill_status billStatus, p.create_time createTime, p.remark, case when p.remain_amount > 0 and p.due_date < curdate() then 1 else 0 end overdueFlag, case when p.due_date is null then 'no_due_date' when p.due_date >= curdate() then 'not_due' when datediff(curdate(), p.due_date) <= 30 then '1_30' when datediff(curdate(), p.due_date) <= 60 then '31_60' when datediff(curdate(), p.due_date) <= 90 then '61_90' else 'over_90' end agingBucket, coalesce(pr.reserved_amount, 0.00) reservedAmount, greatest(p.remain_amount - coalesce(pr.reserved_amount, 0.00), 0.00) availableAmount, si.supplier_invoice_no supplierInvoiceNo, si.purchase_no purchaseNo, si.match_status matchStatus, si.invoice_status invoiceStatus from fin_payable_bill p left join fin_supplier_invoice si on si.payable_no = p.payable_no left join ( select payable_no, sum(greatest(payment_amount - coalesce(paid_amount, 0.00), 0.00)) reserved_amount from fin_payment_request where payment_status in ('submitted', 'approved', 'partially_paid') group by payable_no ) pr on pr.payable_no = p.payable_no
and p.payable_no like concat('%', #{payableNo}, '%') and p.period_code = #{periodCode} and p.counterparty_name like concat('%', #{counterpartyName}, '%') and p.bill_status = #{billStatus} and p.remain_amount > 0 and p.due_date < curdate() and p.remain_amount > 0 and p.due_date between curdate() and date_add(curdate(), interval 7 day) and p.source_type = #{sourceType}
order by case when p.remain_amount > 0 and p.due_date < curdate() then 0 else 1 end, p.due_date, p.payable_id desc

select pr.payment_id paymentId, pr.payment_no paymentNo, pr.source_type sourceType, pr.source_no sourceNo, pr.counterparty_type counterpartyType, pr.counterparty_id counterpartyId, pr.counterparty_name counterpartyName, pr.payable_no payableNo, pr.payment_amount paymentAmount, coalesce(pr.paid_amount, 0.00) paidAmount, greatest(pr.payment_amount - coalesce(pr.paid_amount, 0.00), 0.00) remainAmount, pr.requested_pay_date requestedPayDate, pr.payment_status paymentStatus, pr.approve_by approveBy, pr.approve_time approveTime, pr.create_by createBy, pr.create_time createTime, pr.update_time updateTime, pr.remark from fin_payment_request pr
and pr.payment_no like concat('%', #{paymentNo}, '%') and pr.payable_no like concat('%', #{payableNo}, '%') and pr.counterparty_name like concat('%', #{counterpartyName}, '%') and pr.payment_status = #{paymentStatus}
order by case pr.payment_status when 'submitted' then 0 when 'approved' then 1 when 'partially_paid' then 2 else 3 end, pr.requested_pay_date, pr.payment_id desc

select e.expense_id expenseId, e.expense_no expenseNo, e.fee_type_code feeTypeCode, e.fee_type_name feeTypeName, e.shop_id shopId, e.shop_name shopName, e.sku_id skuId, e.sku_code skuCode, e.order_no orderNo, e.supplier_id supplierId, e.supplier_name supplierName, e.period_code periodCode, e.expense_amount expenseAmount, e.tax_amount taxAmount, e.total_amount totalAmount, e.allocation_dimension allocationDimension, e.expense_status expenseStatus, e.occurred_date occurredDate, e.create_time createTime, e.remark, ap.payable_no payableNo, v.voucher_no voucherNo from fin_expense_bill e left join fin_payable_bill ap on ap.source_type = 'expense' and ap.source_no = e.expense_no left join fin_voucher v on v.source_type = 'expense' and v.source_no = e.expense_no
and e.expense_no like concat('%', #{expenseNo}, '%') and e.period_code = #{periodCode} and e.fee_type_code = #{feeTypeCode} and e.shop_name like concat('%', #{shopName}, '%') and e.expense_status = #{expenseStatus}
order by e.expense_id desc

select voucher_id voucherId, voucher_no voucherNo, period_code periodCode, voucher_date voucherDate, source_type sourceType, source_no sourceNo, summary, debit_amount debitAmount, credit_amount creditAmount, voucher_status voucherStatus, create_time createTime, remark from fin_voucher
and voucher_no like concat('%', #{voucherNo}, '%') and period_code = #{periodCode} and source_no like concat('%', #{sourceNo}, '%') and voucher_status = #{voucherStatus}
order by voucher_id desc

select task_id taskId, task_no taskNo, reconcile_type reconcileType, period_code periodCode,
       shop_id shopId, shop_name shopName, task_status taskStatus, total_count totalCount,
       diff_count diffCount, start_time startTime, finish_time finishTime, create_time createTime, remark
from fin_reconciliation_task

    and task_no like concat('%', #{taskNo}, '%')
    and period_code = #{periodCode}
    and reconcile_type = #{reconcileType}
    and task_status = #{taskStatus}

order by task_id desc

select diff_id diffId, task_id taskId, diff_no diffNo, diff_type diffType, source_type sourceType, source_no sourceNo, expected_amount expectedAmount, actual_amount actualAmount, diff_amount diffAmount, diff_status diffStatus, handle_result handleResult, create_time createTime, remark from fin_reconciliation_diff
and diff_no like concat('%', #{diffNo}, '%') and diff_type = #{diffType} and source_no like concat('%', #{sourceNo}, '%') and diff_status = #{diffStatus}
order by diff_id desc

select close_id closeId, period_code periodCode, close_scope closeScope, check_status checkStatus, close_status closeStatus, order_complete orderComplete, settlement_complete settlementComplete, bank_complete bankComplete, voucher_complete voucherComplete, close_by closeBy, close_time closeTime, create_time createTime, remark from fin_period_close
and period_code like concat('%', #{periodCode}, '%') and close_status = #{closeStatus} and check_status = #{checkStatus}
order by period_code desc, close_id desc

select invoice_id invoiceId, invoice_no invoiceNo, supplier_invoice_no supplierInvoiceNo,
       supplier_id supplierId, invoice_status invoiceStatus
from fin_supplier_invoice
where supplier_id = #{supplierId}
  and supplier_invoice_no = #{supplierInvoiceNo}
limit 1

select close_id closeId, period_code periodCode, close_scope closeScope, check_status checkStatus,
       close_status closeStatus
from fin_period_close
where period_code = #{periodCode}
  and close_scope = #{closeScope}

mapper.insert:
insert into fin_receivable_bill(
    receivable_no, source_type, source_no, counterparty_type, counterparty_id,
    counterparty_name, shop_id, shop_name, period_code, bill_amount, writeoff_amount,
    remain_amount, due_date, bill_status, create_by, create_time, remark
) values (
    #{receivableNo}, #{sourceType}, #{sourceNo}, #{counterpartyType}, #{counterpartyId},
    #{counterpartyName}, #{shopId}, #{shopName}, #{periodCode}, #{billAmount}, #{writeoffAmount},
    #{remainAmount}, #{dueDate}, #{billStatus}, #{createBy}, sysdate(), #{remark}
)

mapper.update:
update fin_cash_flow
set voucher_no = #{voucherNo}, update_by = #{updateBy}, update_time = sysdate()
where flow_no = #{flowNo}

mapper.insert:
insert into fin_writeoff_record(
    writeoff_no, bill_type, bill_no, cash_flow_no, writeoff_amount,
    writeoff_time, operator_name, create_by, create_time, remark
) values (
    #{writeoffNo}, #{billType}, #{billNo}, #{cashFlowNo}, #{writeoffAmount},
    sysdate(), #{operatorName}, #{createBy}, sysdate(), #{remark}
)

insert into fin_payable_bill(
    payable_no, source_type, source_no, counterparty_type, counterparty_id,
    counterparty_name, period_code, bill_amount, writeoff_amount, remain_amount,
    due_date, bill_status, create_by, create_time, remark
) values (
    #{payableNo}, #{sourceType}, #{sourceNo}, #{counterpartyType}, #{counterpartyId},
    #{counterpartyName}, #{periodCode}, #{billAmount}, #{writeoffAmount}, #{remainAmount},
    #{dueDate}, #{billStatus}, #{createBy}, sysdate(), #{remark}
)

insert into fin_payment_request(
    payment_no, source_type, source_no, counterparty_type, counterparty_id,
    counterparty_name, payable_no, payment_amount, paid_amount,
    requested_pay_date, payment_status, create_by, create_time, remark
) values (
    #{paymentNo}, #{sourceType}, #{sourceNo}, #{counterpartyType}, #{counterpartyId},
    #{counterpartyName}, #{payableNo}, #{paymentAmount}, #{paidAmount},
    #{requestedPayDate}, #{paymentStatus}, #{createBy}, sysdate(), #{remark}
)

mapper.update:
update fin_payment_request
set paid_amount = #{paidAmount}, payment_status = #{paymentStatus},
    update_by = #{updateBy}, update_time = sysdate()
where payment_no = #{paymentNo}
  and payment_status = #{expectedStatus}
  and coalesce(paid_amount, 0.00) = #{oldPaidAmount}

mapper.insert:
insert into fin_payment_execute(
    execute_no, payment_no, bank_account_id, cash_flow_no, bank_reference,
    execute_amount, execute_time, execute_status, operator_name,
    create_by, create_time, remark
) values (
    #{executeNo}, #{paymentNo}, #{bankAccountId}, #{cashFlowNo}, #{bankReference},
    #{executeAmount}, #{executeTime}, #{executeStatus}, #{operatorName},
    #{createBy}, sysdate(), #{remark}
)

insert into fin_voucher(
    voucher_no, period_code, voucher_date, source_type, source_no, summary,
    debit_amount, credit_amount, voucher_status, create_by, create_time, remark
) values (
    #{voucherNo}, #{periodCode}, #{voucherDate}, #{sourceType}, #{sourceNo}, #{summary},
    #{debitAmount}, #{creditAmount}, #{voucherStatus}, #{createBy}, sysdate(), #{remark}
)

insert into fin_voucher_entry(
    voucher_id, voucher_no, entry_seq, subject_code, subject_name, direction,
    amount, shop_id, sku_id, counterparty_name, summary
) values (
    #{voucherId}, #{voucherNo}, #{entrySeq}, #{subjectCode}, #{subjectName}, #{direction},
    #{amount}, #{shopId}, #{skuId}, #{counterpartyName}, #{summary}
)

insert into fin_reconciliation_task(
    task_no, reconcile_type, period_code, shop_id, shop_name, task_status,
    start_time, create_by, create_time, remark
) values (
    #{taskNo}, #{reconcileType}, #{periodCode}, #{shopId}, #{shopName}, 'running',
    sysdate(), #{createBy}, sysdate(), #{remark}
)

insert into fin_reconciliation_diff(
    task_id, diff_no, diff_type, source_type, source_no, expected_amount,
    actual_amount, diff_amount, diff_status, handle_result, create_by, create_time, remark
) values (
    #{taskId}, #{diffNo}, #{diffType}, #{sourceType}, #{sourceNo}, #{expectedAmount},
    #{actualAmount}, #{diffAmount}, #{diffStatus}, #{handleResult}, #{createBy}, sysdate(), #{remark}
)

insert into fin_period_close(
    period_code, close_scope, check_status, close_status, create_by, create_time
) values (
    #{periodCode}, #{closeScope}, 'unchecked', 'open', #{createBy}, sysdate()
)
